	input logic clk,
	input logic shift_ena,
	input logic count_ena,
	input logic data,
	input logic reset,
	output logic [3:0] q
);

logic [3:0] shift_reg;
logic [2:0] count;
logic state, state_next;

initial begin
	shift_reg = 4'b0000;
	count = 3'd7;
	state = 1'b0;
end

