	if (reset) begin
		shift_reg <= 4'b0000;
		count <= 3'd7;
		state <= 1'b0;
	end else begin
		case (state)
			1'b0: begin
				if (shift_ena)
					state_next = 1'b1;
				else if (count_ena && count != 0)
					state_next = 1'b10;
				else
