			end
			1'b1: begin
				shift_reg <= {data, shift_reg[3:1]};
				state_next = 1'b0;
			end
			1'b10: begin
				count--;
				if (count == 0)
					state_next = 1'b0;
				else
					state_next = 1'b10;
			end
			default: state_next = 1'b0;
		endcase
	end
end

